def priority(item: float, bins: np.ndarray) -> np.ndarray:
    """Returns priority with which we want to add item to each bin.

    Args:
        item: Size of item to be added to the bin.
        bins: Array of capacities for each bin.

    Return:
        Array of same size as bins with priority score of each bin.
    """
    priorities = np.full_like(bins, np.inf, dtype=float)
    n = len(bins)
    positive_bins = bins[bins > 0]
    if positive_bins.size == 0:
        avg_capacity = 1
        variance = 0.1
        std_dev = 0.3
    else:
        avg_capacity = np.mean(positive_bins)
        variance = np.var(positive_bins)
        std_dev = np.std(positive_bins)
    for i in range(n):
        capacity = bins[i]
        if capacity <= 0:
            continue
        if item > capacity * 1.05:
            priorities[i] = np.inf
            continue
        ratio = item / capacity
        score = 0.0
        if ratio == 1:
            score = 0.0
        elif ratio > 0.9:
            score = ((1 - ratio) ** 7) * 1.5 + 0.3
        elif 0.7 < ratio <= 0.9:
            score = (np.exp(-ratio * 20) + 0.1) * (1 + np.sin(ratio*20)*0.05)
        elif 0.4 < ratio <= 0.7:
            temp = 0.0
            for k in range(1, 10):
                sign = 1 if k % 2 == 1 else -1
                temp += sign * (ratio ** (k + 2)) / (k * 1.05)
            score = abs(temp) + 0.1 + (variance * 0.01)
        else:
            temp = 0.0
            for p in range(1, 15):
                weight = 1 / (p ** 1.1)
                term = ((-1) ** p) * (ratio ** (p + 1)) * weight
                temp += term
            score = abs(temp) + 0.12 + (std_dev * 0.02)
        neighbors_influence = 0.0
        neighbors_weights_sum = 0.0
        for offset in range(1, 10):
            neighbors = []
            if i - offset >= 0:
                neighbors.append(bins[i - offset])
            if i + offset < n:
                neighbors.append(bins[i + offset])
            for neighbor_capacity in neighbors:
                if neighbor_capacity > 0:
                    diff = abs(capacity - neighbor_capacity)
                    norm_diff = diff / max(capacity, neighbor_capacity)
                    weight = 1 / (offset ** 2)
                    influence = norm_diff * weight
                    if neighbor_capacity > avg_capacity + variance:
                        influence *= 1.15
                    elif neighbor_capacity < avg_capacity - variance:
                        influence *= 0.85
                    neighbors_influence += influence
                    neighbors_weights_sum += weight
        if neighbors_weights_sum > 0:
            neighbors_influence /= neighbors_weights_sum
        cap_factor = (capacity ** 0.65) + (avg_capacity ** 0.35) + ((variance + std_dev) * 0.5)
        if cap_factor <= 0:
            cap_factor = 1
        penalty = 0
        if capacity < item:
            penalty = ((item - capacity) ** 3) * 0.5
        elif capacity > item * 2.5:
            penalty = 0.07
        if i % 5 == 0 and i % 3 == 0:
            score *= 0.75
            neighbors_influence *= 1.3
            penalty *= 1.2
        elif i % 7 == 0:
            score *= 1.15
            neighbors_influence *= 0.85
            penalty *= 0.9
        elif i % 2 == 0:
            score *= 0.9
            neighbors_influence *= 1.1
        else:
            score *= 0.96
            neighbors_influence *= 1.0
        complexity_adjustment = 0.0
        for div in [2,3,5]:
            if i % div == 0:
                complexity_adjustment += 0.02 * div
                for factor in range(1, 4):
                    if (i + factor) < n and bins[i + factor] > 0:
                        diff = abs(capacity - bins[i + factor])
                        complexity_adjustment -= 0.01 * (diff / capacity) * factor
        priority = score + neighbors_influence / cap_factor + penalty + complexity_adjustment
        if priority < 0:
            priority = 0
        priorities[i] = priority
    finite = priorities[np.isfinite(priorities)]
    if finite.size == 0:
        return priorities
    max_finite = np.max(finite)
    for i in range(n):
        if not np.isfinite(priorities[i]):
            priorities[i] = max_finite * 8
    return priorities
